import 'package:flutter/material.dart';

class ParableModel {
  final String title;
  final String reference;
  final String theme;
  final String? imagePath;
  final IconData icon;
  final String summary;

  // ── Scholarly fields ───────────────────────────────────────────────────────
  final String verse;           // WEB scripture text
  final String statementInBrief;
  final String centralPointTitle;
  final String centralPoint;
  final String pdfQuestion;
  final List<String> pdfPractices;
  final String audienceContext;
  final String historicalContext;
  final String scholarlyInterpretation;
  final String exegeticalNotes;

  const ParableModel({
    required this.title,
    required this.reference,
    required this.theme,
    this.imagePath,
    required this.icon,
    required this.summary,
    this.verse = '',
    this.statementInBrief = '',
    this.centralPointTitle = '',
    this.centralPoint = '',
    this.pdfQuestion = '',
    this.pdfPractices = const [],
    this.audienceContext = '',
    this.historicalContext = '',
    this.scholarlyInterpretation = '',
    this.exegeticalNotes = '',
  });
}

class ParableGroup {
  final String heading;
  final List<ParableModel> parables;
  const ParableGroup({required this.heading, required this.parables});
}

